        "definedTerm": [
            {
                "@type": "DefinedTerm",
                "name": "Section 14 Companies Act 2013",
                "description": "Charging section for alteration of Articles; contains the proviso that any alteration having the effect of conversion of a public company into a private company shall not be valid unless approved by an order of the Central Government."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 18 Companies Act 2013",
                "description": "Recognises conversion of companies already registered as a change of company type that preserves the body corporate; assets, liabilities, contracts and proceedings carry forward."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 2(68) Private Company Definition",
                "description": "A company that (a) restricts the right to transfer shares, (b) limits members to maximum 200 (excluding past and present employees who became members during employment), (c) prohibits invitation to the public for subscription."
            },
            {
                "@type": "DefinedTerm",
                "name": "Section 117 Filing of Resolutions",
                "description": "Requires filing of special resolutions in Form MGT-14 within 30 days of passing."
            },
            {
                "@type": "DefinedTerm",
                "name": "Rule 41 Companies (Incorporation) Rules 2014",
                "description": "Procedural rules prescribing the full conversion workflow - special resolution, newspaper publication, individual creditor notice, 21-day waiting, RD-1 application, hearing, RD order, INC-28 filing."
            },
            {
                "@type": "DefinedTerm",
                "name": "Form MGT-14",
                "description": "Filing of special resolution with ROC within 30 days; required for any alteration of MOA or AOA."
